<script setup lang="ts">import{Head}from'@inertiajs/vue3';import AuthenticatedLayout from '@/Layouts/AuthenticatedLayout.vue';import Pagination from '@/Components/UI/Pagination.vue';interface Row{id:number;payment_number:string;payment_date:string;amount:string;payment_method:string;bank_name?:string;reference_number?:string;invoice:{id:number;invoice_number:string;billing_name:string};creator:{name:string}}interface P{data:Row[];links:{url:string|null;label:string;active:boolean}[];from:number;to:number;total:number}defineProps<{rows:P}>();const money=(v:string)=>new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',maximumFractionDigits:0}).format(Number(v));</script><template><Head title="Pembayaran"/><AuthenticatedLayout><template #breadcrumb>Transaksi / Pembayaran</template><div class="mb-6"><h1 class="page-title">Pembayaran</h1><p class="page-subtitle">Riwayat pembayaran invoice yang telah tercatat.</p></div><section class="panel"><div class="table-wrap"><table class="data-table"><thead><tr><th>Nomor Pembayaran</th><th>Invoice</th><th>Tanggal</th><th>Nominal</th><th>Metode</th><th>Referensi</th><th>Dibuat Oleh</th></tr></thead><tbody><tr v-for="row in rows.data" :key="row.id"><td class="font-semibold text-sky-600">{{row.payment_number}}</td><td>{{row.invoice.invoice_number}}<div class="text-xs text-slate-400">{{row.invoice.billing_name}}</div></td><td>{{new Date(row.payment_date).toLocaleDateString('id-ID')}}</td><td class="font-semibold">{{money(row.amount)}}</td><td>{{row.payment_method}}</td><td>{{row.reference_number||'-'}}</td><td>{{row.creator.name}}</td></tr><tr v-if="!rows.data.length"><td colspan="7" class="py-12 text-center text-slate-500">Belum ada pembayaran.</td></tr></tbody></table></div><div class="flex justify-between border-t p-4"><span class="text-xs text-slate-500">{{rows.from??0}}–{{rows.to??0}} dari {{rows.total}}</span><Pagination :links="rows.links"/></div></section></AuthenticatedLayout></template>
